/**
 * HybridPopover — configurable overlay panel composing O9Popover with
 * structured filter-list content variants (multi-select, single-select).
 *
 * See descriptors/hybrid-popover.json for the full spec.
 */

import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import type { MouseEvent as ReactMouseEvent, ReactNode, RefObject } from 'react';
import {
  createSortableList,
  createResizeHandle,
  filterItems,
  filterGroups,
  type Placement,
  type SortableHandle,
  type ResizeHandleInstance,
  type ResizeRect,
} from '@o9ds/core';

import O9Popover, {
  type O9PopoverAction,
  type O9PopoverHeaderAction,
} from '../Popover/Popover';
import O9Search from '../Search/Search';
import O9ButtonGroup from '../ButtonGroup/ButtonGroup';

import FilterList from './FilterList';
import EmptyState from './EmptyState';
import type { FilterOptionSelectionKind } from './FilterOption';

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

export const HPOP_MIN_WIDTH = 280;
export const HPOP_DEFAULT_WIDTH = 320;
export const HPOP_MAX_WIDTH = 500;
export const HPOP_MIN_HEIGHT = 272;

const SKELETON_ROW_COUNT = 12;

// ---------------------------------------------------------------------------
// Custom types
// ---------------------------------------------------------------------------

export interface HybridPopoverItem {
  id: string;
  label: string;
  secondaryLabel?: string;
  icon?: string;
  value?: unknown;
  isDisabled?: boolean;
  isExcluded?: boolean;
  isDraggable?: boolean;
  hasInline?: boolean | HybridPopoverItem[] | HybridPopoverInlineConfig;
  isIndeterminate?: boolean;
}

export interface HybridPopoverGroup {
  id: string;
  label?: string;
  isDraggable?: boolean;
  hasSelectAll?: boolean;
  items: HybridPopoverItem[];
}

export interface HybridPopoverSearchConfig {
  variant?: 'default' | 'filter-search';
  placeholder?: string;
  shortcut?: string;
  counter?: boolean;
}

export interface HybridPopoverConditionalConfig {
  value: 'and' | 'or';
  onChange: (value: 'and' | 'or') => void;
}

export interface HybridPopoverEmptyConfig {
  noDataTitle?: string;
  noDataMessage?: string;
  noResultsTitle?: string;
  noResultsMessage?: string;
  noResultsClearLabel?: string;
}

export interface HybridPopoverInlineConfig {
  title?: string;
  items?: HybridPopoverItem[] | HybridPopoverGroup[];
  variant?: 'multi' | 'single';
  hasBackButton?: boolean;
}

// ---------------------------------------------------------------------------
// Reorder / Change meta
// ---------------------------------------------------------------------------

export interface HybridPopoverReorderDetail {
  fromIndex: number;
  toIndex: number;
  fromGroup: string | null;
  toGroup: string | null;
  items: HybridPopoverItem[] | HybridPopoverGroup[];
}

export interface HybridPopoverChangeMeta {
  item: HybridPopoverItem | null;
  action: 'toggle' | 'select-all' | 'group-select-all' | 'apply' | 'reset' | 'clear';
}

// ---------------------------------------------------------------------------
// Imperative handle
// ---------------------------------------------------------------------------

export interface O9HybridPopoverHandle {
  open: () => void;
  close: () => void;
  toggle: () => void;
  isOpen: () => boolean;
  value: (next?: string[] | string | null) => string[] | string | null | void;
  setLoading: (loading: boolean) => void;
  updateItems: (items: HybridPopoverItem[] | HybridPopoverGroup[]) => void;
  reposition: () => void;
}

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

export type HybridPopoverVariant = 'multi' | 'single' | 'boolean' | 'conditional' | 'custom';

export interface O9HybridPopoverProps {
  variant?: HybridPopoverVariant;
  selectionMode?: 'multi' | 'single' | 'none';
  items: HybridPopoverItem[] | HybridPopoverGroup[];
  value?: string[] | string | null;
  defaultValue?: string[] | string | null;
  onChange?: (
    value: string[] | string | null,
    meta: HybridPopoverChangeMeta,
  ) => void;
  commitOn?: 'apply' | 'change';

  search?: false | HybridPopoverSearchConfig;
  conditional?: false | HybridPopoverConditionalConfig;

  hasGlobalSelectAll?: boolean;
  enableReorder?: boolean;
  crossGroupDrag?: boolean;
  onReorder?: (detail: HybridPopoverReorderDetail) => void;

  emptyConfig?: HybridPopoverEmptyConfig;
  actions?: O9PopoverAction[] | false;

  isResizable?: boolean;
  width?: number;
  height?: number | null;
  onResize?: (detail: { width: number; height: number }) => void;
  onResizeCommit?: (detail: { width: number; height: number }) => void;

  title?: string | null;
  hasHeader?: boolean;
  isClosable?: boolean;
  hasBackButton?: boolean;
  onBack?: () => void;
  headerActions?: O9PopoverHeaderAction[];

  placement?: Placement | 'auto';
  offset?: number;
  closeOnOutside?: boolean;

  isLoading?: boolean;
  isOpen?: boolean | null;
  defaultOpen?: boolean;
  onOpenChange?: (isOpen: boolean) => void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;

  triggerRef?: RefObject<HTMLElement | null>;
  renderTrigger?: (props: {
    ref: RefObject<HTMLElement | null>;
    onClick?: (event: ReactMouseEvent) => void;
    'aria-expanded': boolean;
    'aria-controls': string;
    'aria-haspopup': 'dialog';
  }) => ReactNode;

  isInline?: boolean;
  parent?: string | null;

  onApply?: (value: string[] | string | null) => boolean | void;
  onCancel?: () => void;
  onReset?: () => void;

  className?: string;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: HybridPopoverItem[] | HybridPopoverGroup[],
): items is HybridPopoverGroup[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: HybridPopoverItem[] | HybridPopoverGroup[],
): HybridPopoverItem[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as HybridPopoverItem[];
}

function clamp(value: number, min: number, max: number) {
  return Math.min(Math.max(value, min), max);
}

function resolveSelection(
  variant: HybridPopoverVariant,
  selectionMode: O9HybridPopoverProps['selectionMode'],
): FilterOptionSelectionKind {
  if (selectionMode) return selectionMode;
  if (variant === 'multi') return 'multi';
  if (variant === 'single') return 'single';
  return 'multi';
}

function defaultDraft(
  selection: FilterOptionSelectionKind,
  controlled: string[] | string | null | undefined,
  defaultValue: string[] | string | null | undefined,
): string[] | string | null {
  const seed = controlled ?? defaultValue ?? null;
  if (selection === 'multi') {
    return Array.isArray(seed) ? [...seed] : [];
  }
  if (selection === 'single') {
    return typeof seed === 'string' ? seed : null;
  }
  return null;
}

function valuesEqual(
  a: string[] | string | null,
  b: string[] | string | null,
): boolean {
  if (a === b) return true;
  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    return a.every((v, i) => v === b[i]);
  }
  return false;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9HybridPopover = forwardRef<O9HybridPopoverHandle, O9HybridPopoverProps>(
  function O9HybridPopover(props, ref) {
    const {
      variant = 'multi',
      selectionMode,
      items: itemsProp,
      value: controlledValue,
      defaultValue,
      onChange,
      commitOn = 'apply',
      search = { variant: 'filter-search', placeholder: 'Search' },
      conditional = false,
      hasGlobalSelectAll = false,
      enableReorder = false,
      crossGroupDrag = false,
      onReorder,
      emptyConfig,
      actions,
      isResizable = true,
      width = HPOP_DEFAULT_WIDTH,
      height = null,
      onResize,
      onResizeCommit,
      title,
      hasHeader = true,
      isClosable = true,
      hasBackButton = false,
      onBack,
      headerActions,
      placement = 'auto',
      offset = 2,
      closeOnOutside = true,
      isLoading: isLoadingProp = false,
      isOpen: openProp,
      defaultOpen = false,
      onOpenChange,
      onOpen,
      onClose,
      triggerRef,
      renderTrigger,
      isInline = false,
      onApply,
      onCancel,
      onReset,
      className,
    } = props;

    const uid = useId();
    const panelId = `o9ds-hpop-${uid}`;

    // ── Variant warning (boolean | conditional | custom not implemented) ──
    const isUnimplemented =
      variant === 'boolean' || variant === 'conditional' || variant === 'custom';
    const lastWarnedVariantRef = useRef<HybridPopoverVariant | null>(null);
    useEffect(() => {
      if (isUnimplemented && lastWarnedVariantRef.current !== variant) {
        lastWarnedVariantRef.current = variant;
        console.warn(
          `HybridPopover: variant "${variant}" is not yet implemented.`,
        );
      }
    }, [variant, isUnimplemented]);

    const selection = useMemo(
      () => resolveSelection(variant, selectionMode),
      [variant, selectionMode],
    );

    // ── Items state (allows imperative updateItems) ──────────────────────
    const [internalItems, setInternalItems] = useState(itemsProp);
    useEffect(() => {
      setInternalItems(itemsProp);
    }, [itemsProp]);
    const items = internalItems;
    const grouped = isGrouped(items);

    // ── Loading state (allows imperative setLoading) ─────────────────────
    const [internalLoading, setInternalLoading] = useState(isLoadingProp);
    useEffect(() => {
      setInternalLoading(isLoadingProp);
    }, [isLoadingProp]);
    const isLoading = internalLoading;

    // ── Open state (controlled / uncontrolled) ───────────────────────────
    const isControlledOpen = openProp !== undefined && openProp !== null;
    const [internalOpen, setInternalOpen] = useState(defaultOpen);
    const isOpen = isControlledOpen ? !!openProp : internalOpen;

    const setOpen = useCallback(
      (next: boolean) => {
        if (!isControlledOpen) setInternalOpen(next);
        onOpenChange?.(next);
      },
      [isControlledOpen, onOpenChange],
    );

    const handleOpen = useCallback(() => {
      if (isOpen) return;
      if (onOpen?.() === false) return;
      setOpen(true);
    }, [isOpen, onOpen, setOpen]);

    const handleClose = useCallback(() => {
      if (!isOpen) return;
      if (onClose?.() === false) return;
      setOpen(false);
    }, [isOpen, onClose, setOpen]);

    const handleToggle = useCallback(() => {
      if (isOpen) handleClose();
      else handleOpen();
    }, [isOpen, handleOpen, handleClose]);

    // ── Committed value (controlled / uncontrolled) ──────────────────────
    const isControlledValue = controlledValue !== undefined;
    const [internalCommitted, setInternalCommitted] = useState<
      string[] | string | null
    >(() => defaultDraft(selection, undefined, defaultValue));
    const committed = isControlledValue
      ? (controlledValue as string[] | string | null)
      : internalCommitted;

    const setCommitted = useCallback(
      (next: string[] | string | null) => {
        if (!isControlledValue) setInternalCommitted(next);
      },
      [isControlledValue],
    );

    // ── Draft value (always uncontrolled inside the component) ───────────
    const [draft, setDraft] = useState<string[] | string | null>(() =>
      defaultDraft(selection, controlledValue, defaultValue),
    );

    // Reset draft to committed whenever the panel is opened or the
    // committed value changes externally.
    useEffect(() => {
      setDraft(
        defaultDraft(selection, committed as string[] | string | null, null),
      );
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen, selection]);

    useEffect(() => {
      if (isControlledValue) {
        setDraft(
          defaultDraft(selection, controlledValue as string[] | string | null, null),
        );
      }
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [controlledValue, selection]);

    // ── Search query (always internal) ───────────────────────────────────
    const searchEnabled = search !== false;
    const searchCfg: HybridPopoverSearchConfig = useMemo(
      () =>
        searchEnabled
          ? {
              variant: 'filter-search',
              placeholder: 'Search',
              ...(search as HybridPopoverSearchConfig),
            }
          : { placeholder: '' },
      [search, searchEnabled],
    );

    const [query, setQuery] = useState('');

    const filteredItems = useMemo<
      HybridPopoverItem[] | HybridPopoverGroup[]
    >(() => {
      if (!searchEnabled || !query) return items;
      if (grouped) {
        return filterGroups(items as HybridPopoverGroup[], {
          query,
          keys: ['label', 'secondaryLabel'],
        });
      }
      return filterItems(items as HybridPopoverItem[], {
        query,
        keys: ['label', 'secondaryLabel'],
      });
    }, [items, grouped, query, searchEnabled]);

    const flatFiltered = useMemo(() => flattenItems(filteredItems), [filteredItems]);
    const flatAll = useMemo(() => flattenItems(items), [items]);

    const totalCount = flatAll.length;
    const filteredCount = flatFiltered.length;

    const hasAnyDragHandle = useMemo(() => {
      if (!enableReorder) return false;
      return flatAll.some((i) => i.isDraggable !== false);
    }, [enableReorder, flatAll]);

    // ── Selection helpers ────────────────────────────────────────────────
    const draftAsArray = useCallback(
      (): string[] => (Array.isArray(draft) ? draft : []),
      [draft],
    );

    const fireOnChange = useCallback(
      (next: string[] | string | null, meta: HybridPopoverChangeMeta) => {
        onChange?.(next, meta);
      },
      [onChange],
    );

    const updateDraft = useCallback(
      (next: string[] | string | null, meta: HybridPopoverChangeMeta) => {
        setDraft(next);
        if (commitOn === 'change') {
          setCommitted(next);
          fireOnChange(next, meta);
        }
      },
      [commitOn, setCommitted, fireOnChange],
    );

    const handleToggleItem = useCallback(
      (item: HybridPopoverItem) => {
        if (item.isDisabled) return;
        if (selection === 'none') return;
        if (selection === 'multi') {
          const arr = draftAsArray();
          const idx = arr.indexOf(item.id);
          const next = idx === -1 ? [...arr, item.id] : arr.filter((v) => v !== item.id);
          updateDraft(next, { item, action: 'toggle' });
        } else {
          const next = draft === item.id ? null : item.id;
          updateDraft(next, { item, action: 'toggle' });
        }
      },
      [selection, draft, draftAsArray, updateDraft],
    );

    const handleToggleGlobalSelectAll = useCallback(() => {
      if (selection !== 'multi') return;
      const enabled = flatAll.filter((i) => !i.isDisabled).map((i) => i.id);
      if (enabled.length === 0) return;
      const arr = draftAsArray();
      const allSelected = enabled.every((id) => arr.includes(id));
      const next = allSelected
        ? arr.filter((id) => !enabled.includes(id))
        : Array.from(new Set([...arr, ...enabled]));
      updateDraft(next, { item: null, action: 'select-all' });
    }, [selection, flatAll, draftAsArray, updateDraft]);

    const handleToggleGroupSelectAll = useCallback(
      (group: HybridPopoverGroup) => {
        if (selection !== 'multi') return;
        const enabled = group.items.filter((i) => !i.isDisabled).map((i) => i.id);
        if (enabled.length === 0) return;
        const arr = draftAsArray();
        const allSelected = enabled.every((id) => arr.includes(id));
        const next = allSelected
          ? arr.filter((id) => !enabled.includes(id))
          : Array.from(new Set([...arr, ...enabled]));
        updateDraft(next, { item: null, action: 'group-select-all' });
      },
      [selection, draftAsArray, updateDraft],
    );

    // ── Footer actions ───────────────────────────────────────────────────
    const handleApply = useCallback(() => {
      const next = draft;
      const result = onApply?.(next);
      setCommitted(next);
      fireOnChange(next, { item: null, action: 'apply' });
      if (result === false) return false;
      handleClose();
      return undefined;
    }, [draft, onApply, setCommitted, fireOnChange, handleClose]);

    const handleCancel = useCallback(() => {
      setDraft(defaultDraft(selection, committed as string[] | string | null, null));
      setQuery('');
      onCancel?.();
      handleClose();
    }, [committed, selection, onCancel, handleClose]);

    const handleReset = useCallback(() => {
      const cleared = selection === 'multi' ? [] : null;
      setDraft(cleared as string[] | string | null);
      setQuery('');
      if (commitOn === 'change') {
        setCommitted(cleared as string[] | string | null);
        fireOnChange(cleared as string[] | string | null, {
          item: null,
          action: 'reset',
        });
      }
      onReset?.();
    }, [selection, commitOn, setCommitted, fireOnChange, onReset]);

    const builtActions: O9PopoverAction[] | undefined = useMemo(() => {
      if (actions === false) return undefined;
      if (actions) return actions;
      if (isLoading) return undefined;

      const list: O9PopoverAction[] = [];
      list.push({
        id: 'reset',
        label: 'Reset',
        variant: 'tertiary',
        action: () => {
          handleReset();
          return false;
        },
      });
      list.push({
        id: 'cancel',
        label: 'Cancel',
        variant: 'secondary',
        action: () => {
          handleCancel();
          return false;
        },
      });
      list.push({
        id: 'apply',
        label: 'Apply',
        variant: 'primary',
        action: () => {
          const r = handleApply();
          return r;
        },
      });
      return list;
    }, [actions, isLoading, handleReset, handleCancel, handleApply]);

    // ── Search handlers ──────────────────────────────────────────────────
    const handleSearchInput = useCallback((value: string) => {
      setQuery(value);
    }, []);
    const handleSearchClear = useCallback(() => {
      setQuery('');
    }, []);

    // ── Conditional toggle items ─────────────────────────────────────────
    const conditionalItems = useMemo(
      () => [
        { value: 'and', label: 'And' },
        { value: 'or', label: 'Or' },
      ],
      [],
    );

    // ── Sticky header JSX (search + conditional) ─────────────────────────
    const renderStickyHeader = (): ReactNode => {
      if (isLoading) return null;
      if (!searchEnabled && !(selection === 'multi' && conditional)) return null;
      // No-data state should hide the sticky header per task description.
      if (totalCount === 0) return null;

      const counter =
        searchEnabled && searchCfg.counter && query
          ? { current: filteredCount, total: totalCount }
          : null;

      return (
        <div className="o9ds-hpop__sticky">
          {searchEnabled && (
            <div className="o9ds-hpop__search">
              <O9Search
                variant="filter"
                value={query}
                placeholder={searchCfg.placeholder ?? 'Search'}
                shortcut={searchCfg.shortcut}
                counter={counter}
                onSearch={handleSearchInput}
                onChange={handleSearchInput}
                onClear={handleSearchClear}
                isFullWidth
                aria-label="Filter options"
              />
            </div>
          )}
          {selection === 'multi' && conditional && (
            <div className="o9ds-hpop__cond">
              <O9ButtonGroup
                ariaLabel="Combine filters"
                items={conditionalItems}
                value={conditional.value}
                size="sm"
                onChange={(detail) => {
                  const v = detail.value;
                  if (v === 'and' || v === 'or') conditional.onChange(v);
                }}
              />
            </div>
          )}
        </div>
      );
    };

    // ── Body JSX (skeleton | empty | list) ───────────────────────────────
    const listRef = useRef<HTMLDivElement | null>(null);

    const renderBody = (): ReactNode => {
      if (isLoading) {
        return (
          <div className="o9ds-hpop__list" aria-hidden="true">
            {Array.from({ length: SKELETON_ROW_COUNT }, (_, i) => (
              <div key={i} className="o9ds-hpop__skeleton" />
            ))}
          </div>
        );
      }

      if (totalCount === 0) {
        return <EmptyState kind="no-data" config={emptyConfig} />;
      }

      if (filteredCount === 0) {
        return (
          <EmptyState
            kind="no-results"
            config={emptyConfig}
            onClear={handleSearchClear}
          />
        );
      }

      if (isUnimplemented) {
        return null;
      }

      return (
        <FilterList
          ref={listRef}
          items={filteredItems}
          isGrouped={isGrouped(filteredItems)}
          selection={selection}
          draftValue={draft}
          enableReorder={enableReorder}
          hasGlobalSelectAll={hasGlobalSelectAll}
          hasAnyDragHandle={hasAnyDragHandle}
          radioName={panelId}
          ariaLabel={title ?? 'Filter options'}
          onToggleItem={handleToggleItem}
          onToggleGroupSelectAll={handleToggleGroupSelectAll}
          onToggleGlobalSelectAll={handleToggleGlobalSelectAll}
        />
      );
    };

    // ── Panel ref + DnD + Resize wiring ──────────────────────────────────
    const panelRef = useRef<HTMLDivElement | null>(null);
    const sortableRef = useRef<SortableHandle | null>(null);
    const resizeRef = useRef<ResizeHandleInstance | null>(null);

    // Apply initial dimensions to panel
    useLayoutEffect(() => {
      const panel = panelRef.current;
      if (!panel || !isOpen) return;
      const w = clamp(width, HPOP_MIN_WIDTH, HPOP_MAX_WIDTH);
      panel.style.width = `${w}px`;
      if (height != null) {
        const maxH = Math.floor(window.innerHeight * 0.9);
        const h = clamp(height, HPOP_MIN_HEIGHT, maxH);
        panel.style.height = `${h}px`;
      } else {
        panel.style.removeProperty('height');
      }
    }, [isOpen, width, height]);

    // Sortable list wiring
    useEffect(() => {
      if (!isOpen || !enableReorder || isLoading) return;
      const list = listRef.current;
      if (!list) return;

      const handle = createSortableList(list, {
        itemSelector: '.o9ds-hpop__opt',
        handleSelector: '.o9ds-hpop__opt__drag',
        getGroupOf: (el: HTMLElement) => el.dataset.group ?? null,
        allowCrossGroup: crossGroupDrag,
        onCommit: (
          fromIndex: number,
          toIndex: number,
          fromGroup: string | null,
          toGroup: string | null,
        ) => {
          onReorder?.({
            fromIndex,
            toIndex,
            fromGroup,
            toGroup,
            items,
          });
        },
      });
      sortableRef.current = handle;
      return () => {
        handle.destroy();
        sortableRef.current = null;
      };
    }, [isOpen, enableReorder, crossGroupDrag, isLoading, items, onReorder, filteredItems]);

    // Resize handles wiring
    useEffect(() => {
      if (!isOpen || !isResizable) return;
      const panel = panelRef.current;
      if (!panel) return;

      const handle = createResizeHandle(panel, {
        corners: ['bottom-left', 'bottom-right'],
        min: { width: HPOP_MIN_WIDTH, height: HPOP_MIN_HEIGHT },
        max: () => ({
          width: HPOP_MAX_WIDTH,
          height: Math.floor(window.innerHeight * 0.9),
        }),
        viewportPadding: 16,
        onResize: (rect: ResizeRect) => {
          onResize?.(rect);
        },
        onCommit: (rect: ResizeRect) => {
          onResizeCommit?.(rect);
          // Trigger position recalculation in O9Popover (its position
          // watcher observes window resize as a fallback signal).
          window.dispatchEvent(new Event('resize'));
        },
      });
      handle.mount();
      resizeRef.current = handle;
      return () => {
        handle.destroy();
        resizeRef.current = null;
      };
    }, [isOpen, isResizable, onResize, onResizeCommit]);

    // ── Imperative handle ────────────────────────────────────────────────
    useImperativeHandle(
      ref,
      () => ({
        open: () => handleOpen(),
        close: () => handleClose(),
        toggle: () => handleToggle(),
        isOpen: () => isOpen,
        value: (next?: string[] | string | null) => {
          if (next === undefined) {
            return committed as string[] | string | null;
          }
          setCommitted(next);
          setDraft(defaultDraft(selection, next, null));
          if (!valuesEqual(next, committed as string[] | string | null)) {
            fireOnChange(next, { item: null, action: 'apply' });
          }
          return undefined;
        },
        setLoading: (loading: boolean) => setInternalLoading(loading),
        updateItems: (next) => setInternalItems(next),
        reposition: () => window.dispatchEvent(new Event('resize')),
      }),
      [
        handleOpen,
        handleClose,
        handleToggle,
        isOpen,
        committed,
        setCommitted,
        selection,
        fireOnChange,
      ],
    );

    // ── Class string ─────────────────────────────────────────────────────
    const variantClass = `o9ds-hpop--${variant}`;
    const featureClasses = [
      searchEnabled && 'o9ds-hpop--with-search',
      selection === 'multi' && conditional && 'o9ds-hpop--with-conditional',
      isResizable && 'o9ds-hpop--with-resize',
    ].filter(Boolean) as string[];

    const stateClasses: string[] = [];
    if (totalCount === 0) stateClasses.push('o9ds-hpop--no-data');
    else if (filteredCount === 0) stateClasses.push('o9ds-hpop--no-results');

    const composedClassName = [
      'o9ds-hpop',
      variantClass,
      ...featureClasses,
      ...stateClasses,
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Render ───────────────────────────────────────────────────────────
    return (
      <O9Popover
        ref={panelRef}
        variant="edge"
        title={title ?? undefined}
        hasHeader={hasHeader}
        isClosable={isClosable}
        hasBackButton={hasBackButton}
        onBack={onBack}
        headerActions={headerActions}
        placement={placement as O9PopoverProps['placement']}
        offset={offset}
        closeOnOutside={closeOnOutside}
        isLoading={isLoading}
        isOpen={isOpen}
        onOpenChange={(next) => {
          if (next) handleOpen();
          else handleClose();
        }}
        onOpen={onOpen}
        onClose={onClose}
        triggerRef={triggerRef}
        renderTrigger={renderTrigger}
        isInline={isInline}
        stickyHeader={renderStickyHeader()}
        actions={builtActions}
        hasFooter={builtActions !== undefined && builtActions.length > 0}
        className={composedClassName}
        id={panelId}
      >
        {renderBody()}
      </O9Popover>
    );
  },
);

// Local alias to keep the placement type narrow for O9Popover.
type O9PopoverProps = React.ComponentProps<typeof O9Popover>;

O9HybridPopover.displayName = 'O9HybridPopover';

export { O9HybridPopover };
export default O9HybridPopover;
